import{f as e,g as n,J as s}from"./common-03e46d7f.js";const t='{"title":"Jenkins","frontmatter":{"date":"2024-01-07","title":"Jenkins","tags":["work"],"describe":"Jenkins"},"headers":[{"level":2,"title":"前言","slug":"前言"},{"level":2,"title":"Jenkins 解决了什么问题","slug":"jenkins-解决了什么问题"},{"level":2,"title":"Jenkins 部署","slug":"jenkins-部署"}],"relativePath":"docs/work/jenkins-start.md","lastUpdated":1705020036363.7324}';var a={};const i=[s('<h2 id="前言"><a class="header-anchor" href="#前言" aria-hidden="true">#</a> 前言</h2><p>没有运维</p><p>没有钱后端分离，就是打包将项目丢到 tomcat 的 WEBAPP 下</p><p>接着公司招了运维（但只负责管理服务器资源，不管各种项目打包之类的），也开始前后端分离，前端管自己的打包，就是将自己打包的 dist 文件丢到服务器 tomcat 的 WEBAPP 下</p><p>看一下流程：本地合并代码 --&gt; 本地打包 --&gt; 上传服务器</p><p>上传服务器可以分为这几个小步骤：打开 xshell --&gt; 连接服务器 --&gt; 进入 tomcat 目录 --&gt; 通过 ftp 上传本地文件</p><p>为了简化，于是写了一个 node 脚本，通过<code>ssh2-sftp-client</code>将<code>上传服务器</code>这一步骤脚本化</p><p><img src="/blog/_assets/upload-dist.a021593f.png" alt="upload-dist"></p><p>最后只要通过执行<code>yarn upload</code>即可实现打包并上传</p><p>不过用了没多久后，运维同事部署了 jenkins 代替了我们手动打包的过程，只要我们点击部署就可以了，当时就感觉 jenkins 挺方便的，但又觉得和前端没多大关系，也就没学习。</p><p>不过也挺<code>烦</code> jenkins 的，为啥呢？</p><blockquote><p>当时和测试说的最多的就是“我在我这试试.....我这没问题啊，你刷新一下”，趁这个时候，赶紧打包重新部署下，不过慢慢的被眼尖的测试同事发现了，找运维把服务器的密码改了，连不上去了 🙄</p></blockquote><p>**为啥现在学呢？**之前公司的 jenkins 都是另一个前端同事负责，于是这个<code>活</code>就交给我了</p><p>想必有很多人都只是会用 jenkins，而并不了解它，那么接下来就随小弟我一起入门一下吧！</p><h2 id="jenkins-解决了什么问题"><a class="header-anchor" href="#jenkins-解决了什么问题" aria-hidden="true">#</a> Jenkins 解决了什么问题</h2><p>我觉得在了解一个新事物前，应该先了解下它的出现解决了什么问题。</p><p>使用 Jenkins，可以实现一键部署发布。</p><h2 id="jenkins-部署"><a class="header-anchor" href="#jenkins-部署" aria-hidden="true">#</a> Jenkins 部署</h2><p>因为公司的 Jenkins 已经是现成的东西了，想要了解它，就需要自己<strong>动手实践</strong>。</p><p><a href="https://www.jenkins.io/download/" target="_blank" rel="noopener noreferrer">Jenkins 官网</a>提供了多种安装方式： <img src="/blog/_assets/jenkins-install-type.1e46bdaa.png" alt="jenkins-install-type"></p><p><a href="https://www.jenkins.io/zh/doc/" target="_blank" rel="noopener noreferrer">Jenkins 中文帮助文档</a></p>',21)];a.render=function(s,t,a,p,r,o){return e(),n("div",null,i)};export{t as __pageData,a as default};
